/* Evidence: cmem-sized-free-c23-etlvei */
/* Browser practice: PicoC 3.2.2 C89/C90 plus selected C99. */
/* Changed case 8508; native C23 claims require explicit transfer gates. */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>


static int evidence_cmem_sized_free_c23_etlvei(size_t count, int simulate_failure, int *observed) {
  int *values;
  size_t index;
  if (observed == NULL || count == 0 || simulate_failure) return 0;
  values = (int *)calloc(count, sizeof *values);
  if (values == NULL) return 0;
  for (index = 0; index < count; ++index) values[index] = (int)index + 5;
  *observed = values[count - 1];
  free(values);
  return 1;
}

int main(void) {
  int observed = -1;
  int rejected = evidence_cmem_sized_free_c23_etlvei(3, 1, &observed);
  int accepted = evidence_cmem_sized_free_c23_etlvei(3, 0, &observed);
  int invariant = !rejected && accepted && observed == 7;
  printf("heap observed=%d invariant=%d\n", observed, invariant);
  return invariant ? 0 : 1;
}
